var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KING_REPLACER_UNIT_GAUNTLET","text":{"KOREA":"흠. 아무리 경계가 삼엄한 진지여도 안에서 문을 열어 주면 소용없지.","JPN":"ふむ、いくら厳しい警戒態勢が敷かれている陣地でも、中から扉を開けては意味がない。","ENG":"Hmm. It doesn't matter how tightly you guard your fortress if someone on the inside opens the door for your enemy.","TWN":"嗯，即使警戒嚴謹，只要在裡面開門就沒用了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_UNIT_GAUNTLET","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KING_REPLACER_UNIT_GAUNTLET","text":{"KOREA":"지금이 바로 그런 형국이로군.","JPN":"今がまさにそういう状態だ。","ENG":"And that's the case right now.","TWN":"現在就是那樣的情形。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_UNIT_GAUNTLET","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KING_REPLACER_UNIT_GAUNTLET","text":{"KOREA":"적을 끌어들여서 힘을 빌리는 것도 모자라, 이제는 그 적을 신뢰하겠다는 건가?","JPN":"敵を引き入れて力を借りるだけでなく、今ではその敵を信頼するというのか？","ENG":"Not only did you invite your enemy into your midst, but now you're also willing to trust him.","TWN":"拉攏敵人借力還不夠，現在是要信任敵人嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_UNIT_GAUNTLET","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KING_REPLACER_UNIT_GAUNTLET","text":{"KOREA":"만약 내가 네 참모였다면 이런 결정은 목숨을 걸고서라도 반대했을 거다.","JPN":"もし私が君の上官なら、こんな決断は命を懸けてでも反対したはずだ。","ENG":"If I was your adjutant, I would have opposed this even if it killed me.","TWN":"如果我是你的幕僚，我寧願冒著生命危險反對這樣的決定。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_UNIT_GAUNTLET","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KING_REPLACER_UNIT_GAUNTLET","text":{"KOREA":"어제의 적이 오늘의 아군이 될 수 있는 것처럼, 오늘의 아군도 내일의 적이 될 수 있는 법.","JPN":"昨日の敵は今日の友とも言うが、その逆もあり得るのだぞ。","ENG":"Yesterday's enemies can be today's allies. Tomorrow, that can easily be reversed.","TWN":"就像昨天的敵人可以成為今天的朋友一樣，今天的朋友也可以成為明天的敵人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_UNIT_GAUNTLET","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KING_REPLACER_UNIT_GAUNTLET","text":{"KOREA":"그걸 알 만한 자가 이런 대담한 제안을 하다니, 정말이지......","JPN":"そのことを知る者がこんな大胆な提案をするなんて、まったく……","ENG":"You're smart enough to know that, and yet...","TWN":"明白這一點的人居然提出這麼大膽的提議，真是的…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_UNIT_GAUNTLET","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KING_REPLACER_UNIT_GAUNTLET","text":{"KOREA":"......너다운 발상이라는 것 말고는 표현할 길이 없군.","JPN":"……君らしい発想、としか言いようがない。","ENG":"Only you could make such a bold decision.","TWN":"……只能說，除了很像你的處事做風之外，我已經無法用其他的話來形容了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_UNIT_GAUNTLET","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KING_REPLACER_UNIT_GAUNTLET","text":{"KOREA":"나에 대한 너의 신뢰를 거절하진 않겠다. 믿을 수 있다면 어디 믿어 보도록.","JPN":"私に対する君の信頼を拒絶したりはしない。信じれるなら信じてみるがいい。","ENG":"I'm not going to say you shouldn't trust me. Go ahead. Trust me.","TWN":"我不會拒絕你對我的信任。能相信的話，就相信吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_UNIT_GAUNTLET","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KING_REPLACER_UNIT_GAUNTLET","text":{"KOREA":"나 또한, 네가 바라보는 미래의 가능성을 믿어 볼 테니.","JPN":"私も君が望む未来の可能性を信じてみるとしよう。","ENG":"I also want to believe in the possibility of the future you see.","TWN":"我也會相信你所指望的未來的可能性。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_UNIT_GAUNTLET","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};